import React from "react";

function Signup() {
  return (
    <div style={{ padding: "30px" }}>
      <h1>Signup Page</h1>

      <input
        type="text"
        placeholder="Enter Name"
        style={{
          display: "block",
          margin: "10px 0",
          padding: "10px",
        }}
      />

      <input
        type="email"
        placeholder="Enter Email"
        style={{
          display: "block",
          margin: "10px 0",
          padding: "10px",
        }}
      />

      <input
        type="password"
        placeholder="Enter Password"
        style={{
          display: "block",
          margin: "10px 0",
          padding: "10px",
        }}
      />

      <button>Signup</button>
    </div>
  );
}

export default Signup;
